import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"诸病源候论","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/02-魏晋隋唐/03-诸病源候论（巢元方）.md","filePath":"tcm-data/02-魏晋隋唐/03-诸病源候论（巢元方）.md","lastUpdated":1781084559000}'),o={name:"tcm-data/02-魏晋隋唐/03-诸病源候论（巢元方）.md"};function n(i,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="诸病源候论" tabindex="-1">诸病源候论 <a class="header-anchor" href="#诸病源候论" aria-label="Permalink to &quot;诸病源候论&quot;">​</a></h1><blockquote><p>巢元方（约550-630年），隋代医学家 中国第一部病因病机学专著 代表作：《诸病源候论》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：隋大业六年（610年），奉隋炀帝敕令编纂</li><li><strong>卷数</strong>：50卷</li><li><strong>病候</strong>：67门，1739种病候</li><li><strong>学术地位</strong>：<strong>中医第一部系统论述病因病机的专著</strong></li><li><strong>特点</strong>：不论治法、只论病源——&quot;诸病之源头，尽在于此&quot;</li></ul><hr><h2 id="二、核心贡献" tabindex="-1">二、核心贡献 <a class="header-anchor" href="#二、核心贡献" aria-label="Permalink to &quot;二、核心贡献&quot;">​</a></h2><h3 id="_1-病源学体系" tabindex="-1">1. 病源学体系 <a class="header-anchor" href="#_1-病源学体系" aria-label="Permalink to &quot;1. 病源学体系&quot;">​</a></h3><p>巢元方对1739种病候逐一分析其病因、病机、证候表现，建立了完整的病源学体系。</p><h3 id="_2-创新性病因认识" tabindex="-1">2. 创新性病因认识 <a class="header-anchor" href="#_2-创新性病因认识" aria-label="Permalink to &quot;2. 创新性病因认识&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">病证</th><th style="text-align:left;">巢元方的认识</th><th style="text-align:left;">意义</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>寄生虫病</strong></td><td style="text-align:left;">指出由虫引起</td><td style="text-align:left;">超越时代的微生物认识</td></tr><tr><td style="text-align:left;"><strong>疥疮</strong></td><td style="text-align:left;">指出由疥虫引起</td><td style="text-align:left;">最早对疥疮病原的描述</td></tr><tr><td style="text-align:left;"><strong>传染病</strong></td><td style="text-align:left;">指出&quot;乖戾之气&quot;所致</td><td style="text-align:left;">对&quot;戾气&quot;学说的贡献</td></tr><tr><td style="text-align:left;"><strong>过敏</strong></td><td style="text-align:left;">指出与体质有关</td><td style="text-align:left;">最早对过敏的认识</td></tr></tbody></table><h3 id="_3-导引养生" tabindex="-1">3. 导引养生 <a class="header-anchor" href="#_3-导引养生" aria-label="Permalink to &quot;3. 导引养生&quot;">​</a></h3><p>每卷后附<strong>养生导引法</strong>，包括气功、按摩、导引等，是中医养生的重要文献。</p><hr><h2 id="三、经典名言" tabindex="-1">三、经典名言 <a class="header-anchor" href="#三、经典名言" aria-label="Permalink to &quot;三、经典名言&quot;">​</a></h2><blockquote><p><strong>「人之所病，病疾多；医之所病，病道少。」</strong></p></blockquote><blockquote><p><strong>「夫病之生，多从风起。」</strong></p></blockquote><hr><h2 id="四、对后世的影响" tabindex="-1">四、对后世的影响 <a class="header-anchor" href="#四、对后世的影响" aria-label="Permalink to &quot;四、对后世的影响&quot;">​</a></h2><ul><li>唐代《千金方》《外台秘要》大量引用</li><li>宋代《太平圣惠方》以此书为纲</li><li>是中医病名规范化的重要文献</li></ul><hr><p><em>本条目为精简框架版。可扩展至常见病候的病机解读专题。</em></p>',22)])])}const u=e(o,[["render",n]]);export{c as __pageData,u as default};
